/*
 * UTF-8 valid ranges.
 *
 * The UTF-8 encoding spreads the bits of a 32bit word over several
 * bytes. This table gives the ranges that can be held and how they'd
 * be represented.
 *
 * 0x00000000 0x0000007F: 0xxxxxxx
 * 0x00000000 0x000007FF: 110xxxxx 10xxxxxx
 * 0x00000000 0x0000FFFF: 1110xxxx 10xxxxxx 10xxxxxx
 * 0x00000000 0x001FFFFF: 11110xxx 10xxxxxx 10xxxxxx 10xxxxxx
 * 0x00000000 0x03FFFFFF: 111110xx 10xxxxxx 10xxxxxx 10xxxxxx 10xxxxxx
 * 0x00000000 0x7FFFFFFF: 1111110x 10xxxxxx 10xxxxxx 10xxxxxx 10xxxxxx 10xxxxxx
 *
 * There is an additional requirement on UTF-8, in that only the
 * shortest representation of a 32bit value is to be used.  A decoder
 * must not decode sequences that do not satisfy this requirement.
 * Thus the allowed ranges have a lower bound.
 *
 * 0x00000000 0x0000007F: 0xxxxxxx
 * 0x00000080 0x000007FF: 110xxxxx 10xxxxxx
 * 0x00000800 0x0000FFFF: 1110xxxx 10xxxxxx 10xxxxxx
 * 0x00010000 0x001FFFFF: 11110xxx 10xxxxxx 10xxxxxx 10xxxxxx
 * 0x00200000 0x03FFFFFF: 111110xx 10xxxxxx 10xxxxxx 10xxxxxx 10xxxxxx
 * 0x04000000 0x7FFFFFFF: 1111110x 10xxxxxx 10xxxxxx 10xxxxxx 10xxxxxx 10xxxxxx
 *
 * Actual unicode characters are limited to the range 0x0 - 0x10FFFF,
 * 17 planes of 65536 values.  This limits the sequences actually seen
 * even more, to just the following.
 *
 *          0 -     0x7F: 0                   - 0x7F
 *       0x80 -    0x7FF: 0xC2 0x80           - 0xDF 0xBF
 *      0x800 -   0xFFFF: 0xE0 0xA0 0x80      - 0xEF 0xBF 0xBF
 *    0x10000 - 0x10FFFF: 0xF0 0x90 0x80 0x80 - 0xF4 0x8F 0xBF 0xBF
 *
 * Within those ranges the surrogates 0xD800 - 0xDFFF are not allowed.
 *
 * Note that the longest sequence seen with valid usage is 4 bytes,
 * the same a single UTF-32 character.  This makes the UTF-8
 * representation of Unicode strictly smaller than UTF-32.
 *
 * The shortest sequence requirement was introduced by:
 *    Corrigendum #1: UTF-8 Shortest Form
 * It can be found here:
 *    http://www.unicode.org/versions/corrigendum1.html
 *
 */

// C documentation
//
//	/*
//	 * Return the number of bytes used by the current UTF-8 sequence.
//	 * Assumes the input points to the first byte of a valid UTF-8
//	 * sequence.
//	 */
func siutf8clen(cgtls *iqlibc.ppTLS, aas ppuintptr) (cgr ppint32) {

	var aac ppuint8
	pp_ = aac
	aac = iqlibc.ppUint8FromInt8(*(*ppint8)(iqunsafe.ppPointer(aas)))

	return ppint32(1) + iqlibc.ppBoolInt32(iqlibc.ppInt32FromUint8(aac) >= ppint32(0xC0)) + iqlibc.ppBoolInt32(iqlibc.ppInt32FromUint8(aac) >= ppint32(0xE0)) + iqlibc.ppBoolInt32(iqlibc.ppInt32FromUint8(aac) >= ppint32(0xF0))
}

// C documentation
//
//	/*
//	 * Decode a 3-byte UTF-8 sequence.
//	 */
func siutf8decode3(cgtls *iqlibc.ppTLS, aastr ppuintptr) (cgr ppuint32) {

	var aauc ppuint32
	var ccv1, ccv2, ccv3 ppuintptr
	pp_, pp_, pp_, pp_ = aauc, ccv1, ccv2, ccv3

	ccv1 = aastr
	aastr = aastr + 1
	aauc = iqlibc.ppUint32FromInt32(ppint32(*(*ppint8)(iqunsafe.ppPointer(ccv1))) & ppint32(0x0F))
	aauc = aauc << ppuint32(6)
	ccv1 = aastr
	aastr = aastr + 1
	aauc = aauc | iqlibc.ppUint32FromInt32(ppint32(*(*ppint8)(iqunsafe.ppPointer(ccv1)))&ppint32(0x3F))
	aauc = aauc << ppuint32(6)
	ccv1 = aastr
	aastr = aastr + 1
	aauc = aauc | iqlibc.ppUint32FromInt32(ppint32(*(*ppint8)(iqunsafe.ppPointer(ccv1)))&ppint32(0x3F))

	return aauc
}

// C documentation
//
//	/*
//	 * Encode a 3-byte UTF-8 sequence.
//	 */
func siutf8encode3(cgtls *iqlibc.ppTLS, aastr ppuintptr, aaval ppuint32) (cgr ppint32) {

	*(*ppint8)(iqunsafe.ppPointer(aastr + 2)) = iqlibc.ppInt8FromUint32(aaval&ppuint32(0x3F) | ppuint32(0x80))
	aaval = aaval >> ppuint32(6)
	*(*ppint8)(iqunsafe.ppPointer(aastr + 1)) = iqlibc.ppInt8FromUint32(aaval&ppuint32(0x3F) | ppuint32(0x80))
	aaval = aaval >> ppuint32(6)
	*(*ppint8)(iqunsafe.ppPointer(aastr)) = iqlibc.ppInt8FromUint32(aaval | ppuint32(0xE0))

	return ppint32(3)
}

// C documentation
//
//	/*
//	 * utf8trie_t
//	 *
//	 * A compact binary tree, used to decode UTF-8 characters.
//	 *
//	 * Internal nodes are one byte for the node itself, and up to three
//	 * bytes for an offset into the tree.  The first byte contains the
//	 * following information:
//	 *  NEXTBYTE  - flag        - advance to next byte if set
//	 *  BITNUM    - 3 bit field - the bit number to tested
//	 *  OFFLEN    - 2 bit field - number of bytes in the offset
//	 * if offlen == 0 (non-branching node)
//	 *  RIGHTPATH - 1 bit field - set if the following node is for the
//	 *                            right-hand path (tested bit is set)
//	 *  TRIENODE  - 1 bit field - set if the following node is an internal
//	 *                            node, otherwise it is a leaf node
//	 * if offlen != 0 (branching node)
//	 *  LEFTNODE  - 1 bit field - set if the left-hand node is internal
//	 *  RIGHTNODE - 1 bit field - set if the right-hand node is internal
//	 *
//	 * Due to the way utf8 works, there cannot be branching nodes with
//	 * NEXTBYTE set, and moreover those nodes always have a righthand
//	 * descendant.
//	 */
type tnutf8trie_t = ppuint8

// C documentation
//
//	/*
//	 * utf8leaf_t
//	 *
//	 * The leaves of the trie are embedded in the trie, and so the same
//	 * underlying datatype: unsigned char.
//	 *
//	 * leaf[0]: The unicode version, stored as a generation number that is
//	 *          an index into utf8agetab[].  With this we can filter code
//	 *          points based on the unicode version in which they were
//	 *          defined.  The CCC of a non-defined code point is 0.
//	 * leaf[1]: Canonical Combining Class. During normalization, we need
//	 *          to do a stable sort into ascending order of all characters
//	 *          with a non-zero CCC that occur between two characters with
//	 *          a CCC of 0, or at the begin or end of a string.
//	 *          The unicode standard guarantees that all CCC values are
//	 *          between 0 and 254 inclusive, which leaves 255 available as
//	 *          a special value.
//	 *          Code points with CCC 0 are known as stoppers.
//	 * leaf[2]: Decomposition. If leaf[1] == 255, then leaf[2] is the
//	 *          start of a NUL-terminated string that is the decomposition
//	 *          of the character.
//	 *          The CCC of a decomposable character is the same as the CCC
//	 *          of the first character of its decomposition.
//	 *          Some characters decompose as the empty string: these are
//	 *          characters with the Default_Ignorable_Code_Point property.
//	 *          These do affect normalization, as they all have CCC 0.
//	 *
//	 * The decompositions in the trie have been fully expanded, with the
//	 * exception of Hangul syllables, which are decomposed algorithmically.
//	 *
//	 * Casefolding, if applicable, is also done using decompositions.
//	 *
//	 * The trie is constructed in such a way that leaves exist for all
//	 * UTF-8 sequences that match the criteria from the "UTF-8 valid
//	 * ranges" comment above, and only for those sequences.  Therefore a
//	 * lookup in the trie can be used to validate the UTF-8 input.
//	 */
type tnutf8leaf_t = ppuint8

/* Marker for hangul syllable decomposition. */
/* Size of the synthesized leaf used for Hangul syllable decomposition. */

/*
 * Hangul decomposition (algorithm from Section 3.12 of Unicode 6.3.0)
 *
 * AC00;<Hangul Syllable, First>;Lo;0;L;;;;;N;;;;;
 * D7A3;<Hangul Syllable, Last>;Lo;0;L;;;;;N;;;;;
 *
 * SBase = 0xAC00
 * LBase = 0x1100
 * VBase = 0x1161
 * TBase = 0x11A7
 * LCount = 19
 * VCount = 21
 * TCount = 28
 * NCount = 588 (VCount * TCount)
 * SCount = 11172 (LCount * NCount)
 *
 * Decomposition:
 *   SIndex = s - SBase
 *
 * LV (Canonical/Full)
 *   LIndex = SIndex / NCount
 *   VIndex = (Sindex % NCount) / TCount
 *   LPart = LBase + LIndex
 *   VPart = VBase + VIndex
 *
 * LVT (Canonical)
 *   LVIndex = (SIndex / TCount) * TCount
 *   TIndex = (Sindex % TCount)
 *   LVPart = SBase + LVIndex
 *   TPart = TBase + TIndex
 *
 * LVT (Full)
 *   LIndex = SIndex / NCount
 *   VIndex = (Sindex % NCount) / TCount
 *   TIndex = (Sindex % TCount)
 *   LPart = LBase + LIndex
 *   VPart = VBase + VIndex
 *   if (TIndex == 0) {
 *          d = <LPart, VPart>
 *   } else {
 *          TPart = TBase + TIndex
 *          d = <LPart, TPart, VPart>
 *   }
 */

/* Constants */

// C documentation
//
//	/* Algorithmic decomposition of hangul syllable. */
func siutf8hangul(cgtls *iqlibc.ppTLS, aastr ppuintptr, aahangul ppuintptr) (cgr ppuintptr) {

	var aah ppuintptr
	var aali, aasi, aati, aavi ppuint32
	pp_, pp_, pp_, pp_, pp_ = aah, aali, aasi, aati, aavi

	/* Calculate the SI, LI, VI, and TI values. */
	aasi = siutf8decode3(cgtls, aastr) - iqlibc.ppUint32FromInt32(iqlibc.ppInt32FromInt32(mvSB))
	aali = aasi / iqlibc.ppUint32FromInt32(iqlibc.ppInt32FromInt32(mvVC)*iqlibc.ppInt32FromInt32(mvTC))
	aavi = aasi % iqlibc.ppUint32FromInt32(iqlibc.ppInt32FromInt32(mvVC)*iqlibc.ppInt32FromInt32(mvTC)) / iqlibc.ppUint32FromInt32(iqlibc.ppInt32FromInt32(mvTC))
	aati = aasi % iqlibc.ppUint32FromInt32(iqlibc.ppInt32FromInt32(mvTC))

	/* Fill in base of leaf. */
	aah = aahangul
	*(*ppuint8)(iqunsafe.ppPointer(aah)) = ppuint8(2)
	*(*ppuint8)(iqunsafe.ppPointer(aah + 1)) = iqlibc.ppUint8FromInt32(iqlibc.ppInt32FromInt32(mvDECOMPOSE))
	aah = aah + ppuintptr(2)

	/* Add LPart, a 3-byte UTF-8 sequence. */
	aah = aah + ppuintptr(siutf8encode3(cgtls, aah, aali+iqlibc.ppUint32FromInt32(iqlibc.ppInt32FromInt32(mvLB))))

	/* Add VPart, a 3-byte UTF-8 sequence. */
	aah = aah + ppuintptr(siutf8encode3(cgtls, aah, aavi+iqlibc.ppUint32FromInt32(iqlibc.ppInt32FromInt32(mvVB))))

	/* Add TPart if required, also a 3-byte UTF-8 sequence. */
	if aati != 0 {
		aah = aah + ppuintptr(siutf8encode3(cgtls, aah, aati+iqlibc.ppUint32FromInt32(iqlibc.ppInt32FromInt32(mvTB))))
	}

	/* Terminate string. */
	*(*ppuint8)(iqunsafe.ppPointer(aah)) = ppuint8('\000')

	return aahangul
}

// C documentation
//
//	/*
//	 * Use trie to scan s, touching at most len bytes.
//	 * Returns the leaf if one exists, NULL otherwise.
//	 *
//	 * A non-NULL return guarantees that the UTF-8 sequence starting at s
//	 * is well-formed and corresponds to a known unicode code point.  The
//	 * shorthand for this will be "is valid UTF-8 unicode".
